import { useEffect, useRef } from "react";

type RouteList = any[];

export function useUniversalRouter() {
  const routesRef = useRef<RouteList | null>(null);
  const gatsbyNavigateRef = useRef<((to: string) => void) | null>(null);
  const initializedRef = useRef(false);

  useEffect(() => {
    if (initializedRef.current || typeof window === "undefined") return;
    initializedRef.current = true;

    (async () => {
      // ---------- 1) GATSBY DETECTION ----------
      try {
        const gatsbyModuleName = "gatsby";
        // eslint-disable-next-line no-eval
        const gatsby = await eval(`import(${JSON.stringify(gatsbyModuleName)})`);

        if (typeof gatsby.navigate === "function") {
          gatsbyNavigateRef.current = gatsby.navigate;
          return; // <-- IMPORTANT: stop here in Gatsby
        }
      } catch {
        // not Gatsby, keep going
      }

      // ---------- 2) VITE ONLY (hidden from Gatsby’s brain) ----------
      const isVite =
        // @ts-ignore
        typeof window !== "undefined" &&
        !!(window as any).__vite_plugin_react_preamble_installed__;

      if (!isVite) return; // Gatsby exits cleanly here

      try {
        const virtualName = "virtual:" + "generated-pages-react";
        // eslint-disable-next-line no-eval
        const mod = await eval(`import(${JSON.stringify(virtualName)})`);
        routesRef.current = mod.default;
      } catch {
        // truly not Vite, nothing to do
      }
    })();
  }, []);

  const go = (to: string) => {
    if (gatsbyNavigateRef.current) {
      gatsbyNavigateRef.current(to);
      return;
    }
    window.location.assign(to);
  };

  const getRoutes = () => routesRef.current;

  return { go, getRoutes };
}